import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Agentic Memory: A Detailed Breakdown","description":"","frontmatter":{"title":"Agentic Memory: A Detailed Breakdown","date":"2026-03-27T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-03-27-@techwith_ram-110770.md","filePath":"research/tweets/2026-03-27-@techwith_ram-110770.md","lastUpdated":1779796674000}'),i={name:"research/tweets/2026-03-27-@techwith_ram-110770.md"};function s(n,e,l,h,m,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="agentic-memory-a-detailed-breakdown" tabindex="-1">Agentic Memory: A Detailed Breakdown <a class="header-anchor" href="#agentic-memory-a-detailed-breakdown" aria-label="Permalink to &quot;Agentic Memory: A Detailed Breakdown&quot;">​</a></h1><p><strong>來源</strong>: <a href="https://x.com/techwith_ram" target="_blank" rel="noreferrer">@techwith_ram</a> · <a href="https://x.com/techwith_ram/status/2037499938574110770" target="_blank" rel="noreferrer">原始推文</a><br><strong>日期</strong>: 2026-03-27<br><strong>統計</strong>: 👍 595 · 🔁 76 · 🔖 1,512 · 👁 230,601<br><strong>評分</strong>: 7.1/10 · <strong>整合決策</strong>: Agent</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>系統性拆解 LLM Agent 四種記憶類型（In-context、External、Episodic、Parametric），涵蓋架構設計、向量搜尋、遺忘策略與 Python 實作範例。</p><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li><strong>LLM 本質無狀態</strong>；記憶層是讓 Agent 具備連貫感知的唯一手段，缺乏記憶的 Agent 是「失憶的優秀員工」</li><li><strong>四種記憶類型各司其職</strong>：In-context（工作台）、External（持久化 DB）、Episodic（事件日誌）、Parametric（模型權重）</li><li><strong>Retrieval 才是瓶頸</strong>：文章指出「記憶架構 20% 是存儲，80% 是 retrieval design」</li><li><strong>記憶需要主動遺忘策略</strong>：時間衰減公式、寫入時重要性評分、定期合併（consolidation）</li><li><strong>可操作實作</strong>：MemoryStore（ChromaDB + OpenAI embeddings）+ EpisodicLogger Python 範例</li></ol><hr><h2 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h2><ul><li>OpenAI embeddings：1,536 floats，cosine similarity 語意搜尋</li><li>向量庫選型：ChromaDB（本地開發）→ pgvector（已有 Postgres）→ Pinecone / Qdrant（大規模）</li><li>三種遺忘策略：時間衰減（recency + relevance 公式）、寫入時 LLM 重要性評分、夜間合併 job</li><li>EpisodicLogger：記錄每次任務的 task、action、result、timestamp</li></ul><hr><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>程式碼標注「AI-generated」</strong>：品質存疑，直接複用需審查；文章圖示（reflection loop、agent loop 圖）在純文字環境無法呈現</li><li><strong>向量庫選型建議過於簡略</strong>：缺少 latency/throughput benchmark，「serious scale」無具體數字門檻</li><li><strong>Episodic memory 執行細節薄弱</strong>：何時觸發 reflection、如何避免 episode store 膨脹未詳述</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8</td><td>Python 範例 + 工具鏈 + 遺忘策略可直接套用</td></tr><tr><td>B. 創新性 (20%)</td><td>6</td><td>四種記憶分類是業界共識，無突破性觀點</td></tr><tr><td>C. 證據品質 (20%)</td><td>6</td><td>程式碼 AI-generated，缺 benchmark，圖示缺失</td></tr><tr><td>D. 技術深度 (15%)</td><td>7</td><td>覆蓋 retrieval、向量搜尋、管理策略，有足夠廣度</td></tr><tr><td>E. 泛化性 (15%)</td><td>8</td><td>框架可用於任何 LLM stack</td></tr></tbody></table><p><strong>加權總分</strong>: 8×0.3 + 6×0.2 + 6×0.2 + 7×0.15 + 8×0.15 = <strong>7.1/10</strong></p><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>Agent</strong> — 總分 &gt; 6，核心是多步驟自主架構（MemoryStore + EpisodicLogger + 遺忘策略組合），適合整合進 Agent 設計 playbook</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Imagine one day you hire a brilliant freelancer. On her first day, she&#39;s incredible, catches every bug, writes clean docs, &amp; even suggests improvements you hadn&#39;t thought of. You&#39;re impressed.</p><p>On the second day, you walk in &amp; say, &quot;Hey, remember that issue we discussed yesterday?&quot;</p><p>She pauses. Looks at you. Slight smile.</p><p>&quot;Sorry… what issue?&quot;</p><p>No memory. No context. Completely gone. You will be shocked as I am while writing this here.</p><p>That&#39;s exactly how most LLMs behave. Every new conversation is a fresh start. The model doesn&#39;t know who you are, what you&#39;ve built together, or what you discussed even a few minutes ago in another chat window.</p><p>For a simple chatbot, that&#39;s fine. But for an agent, something that runs tasks, makes decisions, and improves over time, this kind of amnesia is a dealbreaker.</p><p>Because real intelligence isn&#39;t just about responding well. It&#39;s about remembering, learning, and building on what came before.</p><p>Memory is what turns a stateless system into something that can actually evolve.</p><h1 id="what-is-agentic-memory-really" tabindex="-1">What is agentic memory, really? <a class="header-anchor" href="#what-is-agentic-memory-really" aria-label="Permalink to &quot;What is agentic memory, really?&quot;">​</a></h1><p>Agentic memory isn&#39;t just one thing. It&#39;s more like a system working behind the scenes, different types of storage, ways to retrieve information, and smart strategies to manage it all so an agent can actually carry context over time.</p><p>The key idea is simple: memory isn&#39;t doing one job; it&#39;s doing three very different ones at the same time.</p><p>➜ Continuity is about identity. It&#39;s how the agent knows who you are, what you prefer, and what you&#39;ve already built together. Without it, every interaction feels like starting from scratch.</p><p>➜ Context is about the task at hand. What just happened, which tool was used, what came back as a result, and what needs to happen next. It&#39;s what keeps multi-step workflows from falling apart.</p><p>➜ Learning is about getting better. Understanding what worked, what didn&#39;t, and slowly improving decisions over time instead of repeating the same mistakes.</p><p>Put together, it makes agents feel consistent, reliable, and a little more intelligent with every interaction.</p><p>A well-designed agent memory system handles all three, using different storage backends for each.</p><h1 id="the-4-types-of-memory" tabindex="-1">The 4-types of memory <a class="header-anchor" href="#the-4-types-of-memory" aria-label="Permalink to &quot;The 4-types of memory&quot;">​</a></h1><p>The field has converged on four distinct memory types. Think of them as four different parts of the brain, each evolved for a specific job.</p><h2 id="_1-in-context-memory" tabindex="-1">1. In-context memory <a class="header-anchor" href="#_1-in-context-memory" aria-label="Permalink to &quot;1. In-context memory&quot;">​</a></h2><p>The context window is your agent&#39;s working desk. Everything on it is instantly accessible. The model can reason over it in a single forward pass. No retrieval step required.</p><p>But the desk has a size limit. Every token costs money and time. And when the session ends, the desk gets wiped clean.</p><p>What lives in context?</p><ul><li>System prompt: agent persona, rules, capabilities, current date/user info</li><li>Conversation history: the back-and-forth so far this session</li><li>Tool call results: outputs from tools the agent just invoked</li><li>Retrieved memories: chunks pulled in from external storage</li><li>Scratchpad: intermediate reasoning (think-step-by-step outputs)</li></ul><p>The sliding window problem</p><p>In long conversations, history accumulates and eventually overflows the context limit. The naive solution of truncating the oldest messages loses important early context. Better strategies:</p><ul><li>Summarization: periodically compress old turns into a brief summary and replace them with the summary</li><li>Selective retention: keep turns that contain key facts, decisions, or tool results; discard small talk.</li><li>Offload to external memory: extract important facts into a vector store, then retrieve them as needed</li></ul><h2 id="_2-external-memory" tabindex="-1">2. External memory <a class="header-anchor" href="#_2-external-memory" aria-label="Permalink to &quot;2. External memory&quot;">​</a></h2><p>External memory is anything that persists outside the model—databases, vector stores, key-value stores, and files. It survives session boundaries. Your agent can remember something from six months ago if you store it right.</p><p>There are two flavors of external storage:</p><p>Structured Store (Exact Lookup): PostgreSQL, Redis, SQLite. You query by key, ID, or SQL. Fast, predictable, great for user profiles, preferences, and structured data.</p><p>Vector Stores (Semantic Search): Pinecone, Chroma, pgvector. You query by meaning, &quot;find memories similar to this concept.&quot; Essential for unstructured notes and episodic recall.</p><p>The retrieval step is a bottleneck. If you don&#39;t retrieve the right memories, the agent behaves as if they don&#39;t exist. Good memory architecture is 20% storage and 80% retrieval design.</p><h2 id="_3-episodic-memory" tabindex="-1">3. Episodic memory <a class="header-anchor" href="#_3-episodic-memory" aria-label="Permalink to &quot;3. Episodic memory&quot;">​</a></h2><p>Episodic memory is the most underappreciated type. While external memory stores facts, episodic memory stores events, specifically the outcomes of past actions.</p><p>The simplest form is a structured log: every time the agent completes a task, it records what happened. Over time, this log becomes a rich source of self-knowledge the agent can consult before making decisions.</p><p>When a new task comes in, the agent retrieves the most semantically similar past episodes and uses them to pick a strategy. This is essentially few-shot learning from personal history rather than from a handcrafted dataset.</p><h2 id="semantic-parametric-memory" tabindex="-1">Semantic/parametric memory <a class="header-anchor" href="#semantic-parametric-memory" aria-label="Permalink to &quot;Semantic/parametric memory&quot;">​</a></h2><p>This is the memory the model was born with. Everything is encoded in weights during training, facts about the world, language patterns, reasoning strategies, coding conventions, and cultural knowledge.</p><p>It&#39;s always there. The agent never has to retrieve it. But it comes with hard limitations:</p><ul><li>Frozen at training time: the model doesn&#39;t know what happened after its cutoff date</li><li>Can&#39;t be updated at runtime: you can&#39;t inject new permanent facts without retraining or fine-tuning</li><li>Opaque: you can&#39;t inspect exactly what the model &quot;knows&quot; or doesn&#39;t</li><li>Hallucination-prone: the model fills gaps with plausible-but-wrong completions.</li></ul><p>For anything time-sensitive, domain-specific, or private, don&#39;t rely on parametric memory. Use external retrieval. Parametric memory is your fallback for general world knowledge when no better source exists.</p><p>The right mental model: parametric memory is the agent&#39;s general education. External, episodic, and in-context memory are the agent&#39;s on-the-job experience. The best agents combine both.</p><h1 id="how-does-memory-flow-through-an-agent-loop" tabindex="-1">How does memory flow through an agent loop? <a class="header-anchor" href="#how-does-memory-flow-through-an-agent-loop" aria-label="Permalink to &quot;How does memory flow through an agent loop?&quot;">​</a></h1><p>Memory operations bookend the LLM call: retrieval before, writing after. The model itself is stateless; the memory system is what gives the illusion of a stateful, aware agent.</p><h1 id="building-a-memory-layer" tabindex="-1">Building a memory layer <a class="header-anchor" href="#building-a-memory-layer" aria-label="Permalink to &quot;Building a memory layer&quot;">​</a></h1><p>Python with OpenAI for embeddings and ChromaDB as local vector store.</p><h2 id="the-memorystore-class" tabindex="-1">The MemoryStore class <a class="header-anchor" href="#the-memorystore-class" aria-label="Permalink to &quot;The MemoryStore class&quot;">​</a></h2><p>Handles writing memories (with embeddings) and semantic retrieval. Foundation everything else sits on.</p><h2 id="the-episodiclogger-class" tabindex="-1">The EpisodicLogger class <a class="header-anchor" href="#the-episodiclogger-class" aria-label="Permalink to &quot;The EpisodicLogger class&quot;">​</a></h2><p>Episode logging layer on top of MemoryStore.</p><h2 id="putting-it-together-a-memory-augmented-agent" tabindex="-1">Putting it together: a memory-augmented agent <a class="header-anchor" href="#putting-it-together-a-memory-augmented-agent" aria-label="Permalink to &quot;Putting it together: a memory-augmented agent&quot;">​</a></h2><p>Combines MemoryStore + EpisodicLogger into a complete agent memory loop.</p><h1 id="vector-databases" tabindex="-1">Vector databases <a class="header-anchor" href="#vector-databases" aria-label="Permalink to &quot;Vector databases&quot;">​</a></h1><p>The heart of any serious memory system. Instead of querying by exact match (like SQL), it finds the nearest neighbors of a vector in high-dimensional space. This is what enables semantic search — finding memories that are conceptually related even if they share no words.</p><h2 id="how-similarity-search-works" tabindex="-1">How similarity search works <a class="header-anchor" href="#how-similarity-search-works" aria-label="Permalink to &quot;How similarity search works&quot;">​</a></h2><p>Every memory is converted to a vector (an array of 1,536 floats with OpenAI&#39;s embedding model). Conceptually similar texts produce similar vectors. When you query, you embed the query and find the closest vectors using cosine similarity.</p><p>Start with ChromaDB for local development. When you&#39;re ready to deploy, evaluate pgvector if you&#39;re already on Postgres with zero extra infrastructure. Use Pinecone or Qdrant when you need serious scale.</p><h1 id="memory-management" tabindex="-1">Memory management <a class="header-anchor" href="#memory-management" aria-label="Permalink to &quot;Memory management&quot;">​</a></h1><p>Real memory systems don&#39;t just accumulate. They curate. An ever-growing, unfocused store degrades over time—retrieval gets noisier, latency climbs, and contradictory memories confuse the agent.</p><p>You need a forgetting strategy. Here are the three main approaches:</p><h2 id="_1-time-based-decay" tabindex="-1">1. Time-based decay <a class="header-anchor" href="#_1-time-based-decay" aria-label="Permalink to &quot;1. Time-based decay&quot;">​</a></h2><p>Older memories are less relevant. Score memories by a combination of recency and semantic relevance.</p><h2 id="_2-importance-scoring-at-write-time" tabindex="-1">2. Importance scoring at write time <a class="header-anchor" href="#_2-importance-scoring-at-write-time" aria-label="Permalink to &quot;2. Importance scoring at write time&quot;">​</a></h2><p>When storing a memory, ask the model to score its own output for importance. Only store high-scoring items. This filters noise at the source.</p><h2 id="_3-periodic-consolidation" tabindex="-1">3. Periodic consolidation <a class="header-anchor" href="#_3-periodic-consolidation" aria-label="Permalink to &quot;3. Periodic consolidation&quot;">​</a></h2><p>Run a nightly job that merges duplicate or highly similar memories into a single canonical summary. This is analogous to how human sleep consolidates memories.</p><h1 id="final-thoughts" tabindex="-1">Final Thoughts <a class="header-anchor" href="#final-thoughts" aria-label="Permalink to &quot;Final Thoughts&quot;">​</a></h1><p>At the end of the day, memory is what makes an AI feel less like a tool &amp; more like a partner. Without it, every interaction starts from zero. With it, an agent can understand, adapt, and improve over time.</p><p>The real power isn&#39;t just in the model; it&#39;s in how you design what the model remembers, what it forgets, and how it uses that information.</p><p>Build the memory layer right, and everything else becomes smarter.</p><p><em>Codes are AI-generated.</em></p>',95)])])}const g=t(i,[["render",s]]);export{p as __pageData,g as default};
